-- Add new schema named "core"
CREATE SCHEMA "core";
-- Create "users" table
CREATE TABLE "core"."users" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "username" character varying NOT NULL,
  "name" character varying NOT NULL DEFAULT '',
  "email" character varying NOT NULL DEFAULT '',
  "phone" character varying NULL,
  "password" character varying NOT NULL,
  "role" character varying NOT NULL DEFAULT 'User',
  "refresh_token" character varying NULL,
  "refresh_token_expire_at" timestamptz NULL,
  "license_expire_date" timestamptz NULL,
  "last_login" timestamptz NULL,
  "active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "users_username_key" to table: "users"
CREATE UNIQUE INDEX "users_username_key" ON "core"."users" ("username");
-- Add new schema named "public"
CREATE SCHEMA IF NOT EXISTS "public";
-- Set comment to schema: "public"
COMMENT ON SCHEMA "public" IS 'standard public schema';
-- Create "company_details" table
CREATE TABLE "core"."company_details" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "company_code" bigint NOT NULL,
  "name" character varying NOT NULL DEFAULT '',
  "address" character varying NULL,
  "phone" character varying NULL,
  "fax" character varying NULL,
  "mobile_phone" character varying NULL,
  "email" character varying NULL,
  "website" character varying NULL,
  "yds_address" character varying NULL,
  "yds_phone" character varying NULL,
  "yds_mobile_phone" character varying NULL,
  "yds_email" character varying NULL,
  "yds_website" character varying NULL,
  "tax_admin" character varying NULL,
  "tax_no" character varying NULL,
  "chamber_info" character varying NULL,
  "chamber_register_no" character varying NULL,
  "visa_date" timestamptz NULL,
  "visa_end_date" timestamptz NULL,
  "visa_finished_for90days" boolean NULL DEFAULT false,
  "core_person_absent90days" boolean NULL DEFAULT false,
  "is_closed" boolean NOT NULL DEFAULT false,
  "owner_name" character varying NULL,
  "owner_tc_no" character varying NULL,
  "owner_address" character varying NULL,
  "owner_phone" character varying NULL,
  "owner_email" character varying NULL,
  "owner_register_no" character varying NULL,
  "owner_career" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create "company_tokens" table
CREATE TABLE "core"."company_tokens" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "ydk_username" character varying NULL,
  "ydk_password" character varying NULL,
  "token" character varying NULL,
  "department_id" bigint NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "company_id" bigint NULL,
  PRIMARY KEY ("id")
);
-- Create index "company_tokens_department_id_key" to table: "company_tokens"
CREATE UNIQUE INDEX "company_tokens_department_id_key" ON "core"."company_tokens" ("department_id");
-- Create "company_users" table
CREATE TABLE "core"."company_users" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "company_id" bigint NULL,
  "user_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "company_users_users_companies" FOREIGN KEY ("user_id") REFERENCES "core"."users" ("id") ON UPDATE NO ACTION ON DELETE SET NULL
);
-- Create index "companyuser_user_id_company_id" to table: "company_users"
CREATE UNIQUE INDEX "companyuser_user_id_company_id" ON "core"."company_users" ("user_id", "company_id");
-- Create "company_engineers" table
CREATE TABLE "core"."company_engineers" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL DEFAULT 'İSİM YOK',
  "tc_no" character varying NULL,
  "phone" character varying NULL,
  "email" character varying NULL,
  "address" character varying NULL,
  "career" character varying NULL,
  "position" character varying NULL,
  "register_no" character varying NULL,
  "cert_no" character varying NULL,
  "ydsid" bigint NULL,
  "employment" timestamptz NULL,
  "status" boolean NOT NULL DEFAULT true,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "company_id" bigint NULL,
  PRIMARY KEY ("id")
);
-- Create index "company_engineers_ydsid_key" to table: "company_engineers"
CREATE UNIQUE INDEX "company_engineers_ydsid_key" ON "core"."company_engineers" ("ydsid");
-- Create "job_authors" table
CREATE TABLE "core"."job_authors" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "yibf_no" bigint NULL,
  "static" character varying NULL,
  "mechanic" character varying NULL,
  "electric" character varying NULL,
  "architect" character varying NULL,
  "geotechnical_engineer" character varying NULL,
  "geotechnical_geologist" character varying NULL,
  "geotechnical_geophysicist" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "job_authors_yibf_no_key" to table: "job_authors"
CREATE UNIQUE INDEX "job_authors_yibf_no_key" ON "core"."job_authors" ("yibf_no");
-- Create "job_contractors" table
CREATE TABLE "core"."job_contractors" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL DEFAULT '',
  "tc_no" character varying NULL,
  "register_no" character varying NULL,
  "address" character varying NULL,
  "tax_no" character varying NULL,
  "mobile_phone" character varying NULL,
  "phone" character varying NULL,
  "email" character varying NULL,
  "person_type" character varying NULL,
  "ydsid" bigint NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "job_contractors_ydsid_key" to table: "job_contractors"
CREATE UNIQUE INDEX "job_contractors_ydsid_key" ON "core"."job_contractors" ("ydsid");
-- Create "job_details" table
CREATE TABLE "core"."job_details" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "yibf_no" bigint NOT NULL,
  "title" character varying NULL,
  "administration" character varying NULL,
  "state" character varying NULL,
  "island" character varying NULL,
  "parcel" character varying NULL,
  "sheet" character varying NULL,
  "contract_date" timestamptz NULL,
  "start_date" timestamptz NULL,
  "license_date" timestamptz NULL,
  "license_no" character varying NULL,
  "distribution_date" timestamptz NULL,
  "completion_date" timestamptz NULL,
  "land_area" double precision NULL,
  "total_area" double precision NULL,
  "construction_area" double precision NULL,
  "left_area" double precision NULL,
  "yds_address" character varying NULL,
  "address" character varying NULL,
  "building_class" character varying NULL,
  "building_type" character varying NULL,
  "level" double precision NULL,
  "unit_price" double precision NULL,
  "floor_count" bigint NULL,
  "bks_reference_no" character varying NULL,
  "coordinates" character varying NULL,
  "folder_no" character varying NULL,
  "uploaded_file" boolean NULL DEFAULT false,
  "industry_area" boolean NULL DEFAULT false,
  "cluster_structure" boolean NULL DEFAULT false,
  "is_license_expired" boolean NULL DEFAULT false,
  "is_completed" boolean NULL DEFAULT false,
  "note" text NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "start_note" character varying NULL,
  PRIMARY KEY ("id")
);
-- Create index "job_details_yibf_no_key" to table: "job_details"
CREATE UNIQUE INDEX "job_details_yibf_no_key" ON "core"."job_details" ("yibf_no");
-- Create "job_owners" table
CREATE TABLE "core"."job_owners" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL DEFAULT '',
  "address" character varying NULL,
  "tc_no" character varying NULL,
  "tax_admin" character varying NULL,
  "tax_no" character varying NULL,
  "phone" character varying NULL,
  "email" character varying NULL,
  "ydsid" bigint NULL,
  "shareholder" boolean NOT NULL DEFAULT false,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "job_owners_ydsid_key" to table: "job_owners"
CREATE UNIQUE INDEX "job_owners_ydsid_key" ON "core"."job_owners" ("ydsid");
-- Create "job_progresses" table
CREATE TABLE "core"."job_progresses" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "yibf_no" bigint NOT NULL,
  "one" bigint NULL DEFAULT 0,
  "two" bigint NULL DEFAULT 0,
  "three" bigint NULL DEFAULT 0,
  "four" bigint NULL DEFAULT 0,
  "five" bigint NULL DEFAULT 0,
  "six" bigint NULL DEFAULT 0,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create "job_supervisors" table
CREATE TABLE "core"."job_supervisors" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NULL,
  "address" character varying NULL,
  "phone" character varying NULL,
  "email" character varying NULL,
  "tc_no" character varying NULL,
  "position" character varying NULL,
  "career" character varying NULL,
  "register_no" character varying NULL,
  "social_security_no" character varying NULL,
  "school_graduation" character varying NULL,
  "ydsid" bigint NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "job_supervisors_ydsid_key" to table: "job_supervisors"
CREATE UNIQUE INDEX "job_supervisors_ydsid_key" ON "core"."job_supervisors" ("ydsid");
-- Create "job_relations" table
CREATE TABLE "core"."job_relations" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "yibf_no" bigint NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "company_id" bigint NULL,
  "static_id" bigint NULL,
  "mechanic_id" bigint NULL,
  "electric_id" bigint NULL,
  "inspector_id" bigint NULL,
  "architect_id" bigint NULL,
  "controller_id" bigint NULL,
  "mechaniccontroller_id" bigint NULL,
  "electriccontroller_id" bigint NULL,
  "author_id" bigint NULL,
  "contractor_id" bigint NULL,
  "job_id" bigint NULL,
  "owner_id" bigint NULL,
  "progress_id" bigint NULL,
  "supervisor_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "job_relations_company_engineers_architects" FOREIGN KEY ("architect_id") REFERENCES "core"."company_engineers" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_company_engineers_controllers" FOREIGN KEY ("controller_id") REFERENCES "core"."company_engineers" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_company_engineers_electriccontrollers" FOREIGN KEY ("electriccontroller_id") REFERENCES "core"."company_engineers" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_company_engineers_electrics" FOREIGN KEY ("electric_id") REFERENCES "core"."company_engineers" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_company_engineers_inspectors" FOREIGN KEY ("inspector_id") REFERENCES "core"."company_engineers" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_company_engineers_mechaniccontrollers" FOREIGN KEY ("mechaniccontroller_id") REFERENCES "core"."company_engineers" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_company_engineers_mechanics" FOREIGN KEY ("mechanic_id") REFERENCES "core"."company_engineers" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_company_engineers_statics" FOREIGN KEY ("static_id") REFERENCES "core"."company_engineers" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_job_authors_authors" FOREIGN KEY ("author_id") REFERENCES "core"."job_authors" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_job_contractors_contractors" FOREIGN KEY ("contractor_id") REFERENCES "core"."job_contractors" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_job_details_relations" FOREIGN KEY ("job_id") REFERENCES "core"."job_details" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_job_owners_owners" FOREIGN KEY ("owner_id") REFERENCES "core"."job_owners" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_job_progresses_progress" FOREIGN KEY ("progress_id") REFERENCES "core"."job_progresses" ("id") ON UPDATE NO ACTION ON DELETE SET NULL,
  CONSTRAINT "job_relations_job_supervisors_supervisors" FOREIGN KEY ("supervisor_id") REFERENCES "core"."job_supervisors" ("id") ON UPDATE NO ACTION ON DELETE SET NULL
);
-- Create index "job_relations_job_id_key" to table: "job_relations"
CREATE UNIQUE INDEX "job_relations_job_id_key" ON "core"."job_relations" ("job_id");
-- Create "job_floors" table
CREATE TABLE "core"."job_floors" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "yibf_no" bigint NOT NULL,
  "name" character varying NOT NULL DEFAULT '',
  "metre" character varying NOT NULL DEFAULT '',
  "mold_date" timestamptz NULL,
  "concrete_date" timestamptz NULL,
  "samples" bigint NULL,
  "concrete_class" character varying NULL,
  "week_result" character varying NULL,
  "month_result" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "relations_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "job_floors_job_relations_floors" FOREIGN KEY ("relations_id") REFERENCES "core"."job_relations" ("id") ON UPDATE NO ACTION ON DELETE SET NULL
);
-- Create "job_payments" table
CREATE TABLE "core"."job_payments" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "yibf_no" bigint NOT NULL DEFAULT 0,
  "payment_no" bigint NULL DEFAULT 0,
  "payment_date" timestamptz NOT NULL,
  "payment_type" character varying NULL,
  "state" character varying NULL,
  "level_request" double precision NULL,
  "level_approve" double precision NULL,
  "amount" numeric(12,2) NULL,
  "at_municipality" boolean NULL DEFAULT false,
  "municipality_delivery_date" timestamptz NULL,
  "invoice_issued" boolean NULL DEFAULT false,
  "invoice_issued_date" timestamptz NULL,
  "invoice_received" boolean NULL DEFAULT false,
  "invoice_received_date" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "relations_id" bigint NULL,
  "invoice_received_amount" numeric(12,2) NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "job_payments_job_relations_payments" FOREIGN KEY ("relations_id") REFERENCES "core"."job_relations" ("id") ON UPDATE NO ACTION ON DELETE SET NULL
);
-- Create "job_receipts" table
CREATE TABLE "core"."job_receipts" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "yibf_no" bigint NOT NULL DEFAULT 0,
  "receipt_date" timestamptz NOT NULL,
  "amount" double precision NULL DEFAULT 0,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "relations_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "job_receipts_job_relations_receipts" FOREIGN KEY ("relations_id") REFERENCES "core"."job_relations" ("id") ON UPDATE NO ACTION ON DELETE SET NULL
);
